function maxSatisfaction(satisfaction) {
    satisfaction.sort((a, b) => b - a);
    let ans = 0, total = 0, sum = 0;
    for (let i of satisfaction) {
        total += i;
        if (total > 0) {
            sum += total;
            ans = Math.max(ans, sum);
        }
    }
    return ans;
}
```

    1. Sort the satisfaction array in descending order.
2. Initialize `ans`, `total`, and `sum` as zero.
3. Iterate through the satisfaction array, adding each element to `total`.
4. If `total` is greater than zero, add `total` to `sum`. Set `ans` as the maximum of `ans` and `sum`.
5. Return `ans` as the maximum sum of like-time coefficients.

